1167→+    /// Append multiple events to the durable log under one connection lock.
1168→+    pub fn append_events(&self, events: &[AppendEvent]) -> Result<Vec<i64>> {
1169→+        if events.is_empty() {
1170→+            return Ok(Vec::new());
1171→+        }
1172→+
1173→+        self.with_connection(|conn| {
1174→+            conn.execute_batch("BEGIN IMMEDIATE TRANSACTION")
1175→+                .context("failed to begin event-log append transaction")?;
1176→+
1177→+            let result = (|| -> Result<Vec<i64>> {
1178→+                let mut seqs = Vec::with_capacity(events.len());
1179→+                let mut stmt = conn
1180→+                    .prepare(
1181→+                        "INSERT INTO event_log (run_id, task_id, agent_id, event_type, payload, created_at)
1182→+                         VALUES (?1, ?2, ?3, ?4, ?5, ?6)",
1183→+                    )
1184→+                    .context("failed to prepare batched event-log insert")?;
1185→+
1186→+                for event in events {
1187→+                    stmt.execute(params![
1188→+                        event.run_id,
1189→+                        event.task_id,
1190→+                        event.agent_id,
1191→+                        event.event_type,
1192→+                        event.payload,
1193→+                        event.created_at.to_rfc3339(),
1194→+                    ])
1195→+                    .with_context(|| {
1196→+                        format!(
1197→+                            "failed to append event `{}` for run `{}`",
1198→+                            event.event_type, event.run_id
1199→+                        )
1200→+                    })?;
1201→+                    seqs.push(conn.last_insert_rowid());
1202→+                }
1203→+
1204→+                Ok(seqs)
1205→+            })();
1206→+
1207→+            match result {
1208→+                Ok(seqs) => {
1209→+                    conn.execute_batch("COMMIT")
1210→+                        .context("failed to commit event-log append transaction")?;
1211→+                    Ok(seqs)
1212→+                }
1213→+                Err(error) => {
1214→+                    let _ = conn.execute_batch("ROLLBACK");
1215→+                    Err(error)
1216→+                }
1217→+            }
1218→+        })
